#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

#ifndef class_T
#define class_T float
#endif

#ifdef ENABLE_HP
#define CONV_INT(i) ((class_T)((half)(i), (half)(i)))
#define EQUAL_T(a, b) (all((a) == (b)))
#else
#define CONV_INT(i) ((class_T)(i))
#define EQUAL_T(a, b) ((a) == (b))
#endif

inline class_T MAD_T(const class_T a, const class_T b, const class_T c) {
  return a * b + c;
}

__kernel void benchmark_func(const class_T seed, __global class_T* g_data) {
  const uint blockSize = (uint)blockdim;

#ifdef BLOCK_STRIDED
  const int stride = (int)blockSize;
  int idx = (int)(get_group_id(0) * blockSize * (uint)ELEMENTS_PER_THREAD +
                  get_local_id(0));
  const int big_stride =
      (int)(get_num_groups(0) * blockSize * (uint)ELEMENTS_PER_THREAD);
#else
  const int stride = (int)get_global_size(0);
  int idx = (int)get_global_id(0);
  const int big_stride = (int)(get_global_size(0) * (uint)ELEMENTS_PER_THREAD);
#endif

  class_T tmps[ELEMENTS_PER_THREAD];

  for (int k = 0; k < FUSION_DEGREE; k++) {
    for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
      tmps[j] = g_data[idx + j * stride + k * big_stride];
      for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
        tmps[j] = MAD_T(tmps[j], tmps[j], seed);
      }
    }

    class_T sum = CONV_INT(0);
    for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
      sum = MAD_T(tmps[j], tmps[j + 1], sum);
    }

    if (EQUAL_T(sum, CONV_INT(-1))) {
      g_data[idx + k * big_stride] = sum;
    }
  }
}
